import{_ as t,o,c as a,a3 as n}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"61. Replacement Of Doctors When On Leave","description":"","frontmatter":{"title":"61. Replacement Of Doctors When On Leave","eba":"Medical Specialists 2022-2026","topics":["leave","staffing","workload"]},"headers":[],"relativePath":"ebas/medical-specialists/leave/61-replacement-of-doctors-when-on-leave.md","filePath":"ebas/medical-specialists/leave/61-replacement-of-doctors-when-on-leave.md"}'),r={name:"ebas/medical-specialists/leave/61-replacement-of-doctors-when-on-leave.md"};function s(l,e,i,c,p,h){return o(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="_61-replacement-of-doctors-when-on-leave" tabindex="-1">61. Replacement Of Doctors When On Leave <a class="header-anchor" href="#_61-replacement-of-doctors-when-on-leave" aria-label="Permalink to &quot;61. Replacement Of Doctors When On Leave&quot;">​</a></h1><p><strong>61.1</strong> Where a Doctor is absent on planned or unplanned leave, the Health Service will replace the Doctor if not replacing will result or will likely result in an unreasonable workload.</p><p><strong>61.2</strong> Except where the Health Service has already decided to replace the Doctor on leave, the Health Service must, as soon as practicable in the circumstances and with no less than two weeks’ notice where there is already notice of the leave, consult with Doctors affected by the absence regarding the workload impact when considering a replacement for a Doctor on leave. The Health Service will record the outcome of this consultation in writing (for example, as an email to the affected Doctors).</p><p><strong>61.3</strong> Where a Doctor on leave is replaced, the Health Service is responsible for finding the replacement.</p><p><strong>61.4</strong> For the purpose of this clause, ‘unreasonable workload’ means being unable to perform all aspects of their position and/or role during their ordinary hours of work, informed by consultation in writing with the affected Doctor/s.</p><p><strong>61.5</strong> If replacement of a Doctor is not possible, the Health Service must take reasonable steps to manage the workload of the remaining team. This could include re-prioritisation or amendments to services.</p><p>COMMITMENT</p><p>Plain language terms: leave cover.</p>',8)])])}const m=t(r,[["render",s]]);export{f as __pageData,m as default};
